+function findConditionalOption(usage: Usage):
+  | (Extract<UsageTerm, { type: "option" }> & { dependsOn: OptionDependency })
+  | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn != null) return term as Extract<
+      UsageTerm,
+      { type: "option" }
+    > & { dependsOn: OptionDependency };
+    if (term.type === "optional" || term.type === "multiple") {
+      const found = findConditionalOption(term.terms);
+      if (found) return found;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const found = findConditionalOption(terms);
+        if (found) return found;
+      }
+    }
+  }
+  return undefined;
+}
+
+function valueFromState(state: unknown): unknown {
+  if (Array.isArray(state)) return state.length === 1 ? valueFromState(state[0]) : undefined;
+  if (isDependencySourceState(state)) return valueFromState(state.result);
+  if (state !== null && typeof state === "object" && "success" in state) {
+    const result = state as { success?: unknown; value?: unknown };
+    return result.success === true ? result.value : undefined;
+  }
+  return undefined;
+}
+
+function dependencyConditions(dependency: OptionDependency): readonly OptionDependencyCondition[] {
+  if (dependency.option != null) {
+    return [{ option: dependency.option, ...(Object.hasOwn(dependency, "value") && { value: dependency.value }) }];
+  }
+  return [];
+}
+
+function isConditionSatisfied(
+  condition: OptionDependencyCondition,
+  fieldByOption: ReadonlyMap<string, string | symbol>,
+  valuesByField: ReadonlyMap<string | symbol, unknown>,
+): boolean {
+  const field = fieldByOption.get(condition.option);
+  if (field == null) return false;
+  const value = valuesByField.get(field);
+  return Object.hasOwn(condition, "value") ? value === condition.value : Boolean(value);
+}
+
+function isDependencySatisfied(
+  dependency: OptionDependency,
+  fieldByOption: ReadonlyMap<string, string | symbol>,
+  valuesByField: ReadonlyMap<string | symbol, unknown>,
+): boolean {
+  const single = dependencyConditions(dependency);
+  if (single.length > 0) return single.every((condition) =>
+    isConditionSatisfied(condition, fieldByOption, valuesByField)
+  );
+  if (dependency.allOf != null && !dependency.allOf.every((condition) =>
+    isConditionSatisfied(condition, fieldByOption, valuesByField)
+  )) return false;
+  if (dependency.anyOf != null && !dependency.anyOf.some((condition) =>
+    isConditionSatisfied(condition, fieldByOption, valuesByField)
+  )) return false;
+  return dependency.allOf != null || dependency.anyOf == null;
+}
+
+function dependencyError(
+  dependency: OptionDependency,
+  fieldByOption: ReadonlyMap<string, string | symbol>,
+  namesByField: ReadonlyMap<string | symbol, readonly string[]>,
+): Message {
+  const condition = dependencyConditions(dependency)[0] ?? dependency.allOf?.[0] ?? dependency.anyOf?.[0];
+  const field = condition == null ? undefined : fieldByOption.get(condition.option);
+  const name = field == null ? condition?.option ?? "unknown" : namesByField.get(field)?.[0] ?? condition!.option;
+  return condition != null && Object.hasOwn(condition, "value")
+    ? message`Option requires option ${eOptionName(name)} to equal ${String(condition.value)}.`
+    : message`Option requires option ${eOptionName(name)}.`;
+}
